/**
 * ResetPasswordForm Component
 *
 * パスワードリセットフォームコンポーネント。
 * 新しいパスワードとパスワード確認の入力とバリデーションを提供します。
 *
 * 使用例:
 * ```tsx
 * <ResetPasswordForm token="reset-token-here" onSuccess={() => navigate('/login')} />
 * ```
 */

import React, { useState } from 'react';
import { usePasswordReset } from '../hooks/usePasswordReset';
import InputField from './InputField';
import Button from './Button';
import ErrorMessage from './ErrorMessage';
import { calculatePasswordStrength } from '../utils/validation';
import { handleNetworkError } from '../utils/errors';

export interface ResetPasswordFormProps {
  /** リセットトークン */
  token: string;
  /** リセット成功時のコールバック */
  onSuccess?: () => void;
  /** リセット失敗時のコールバック */
  onError?: (error: string) => void;
}

interface FormData {
  newPassword: string;
  confirmPassword: string;
}

/**
 * ResetPasswordFormコンポーネント
 * パスワードリセットフォームを提供します
 */
const ResetPasswordForm: React.FC<ResetPasswordFormProps> = ({ token, onSuccess, onError }) => {
  const { resetPassword } = usePasswordReset();
  const [formData, setFormData] = useState<FormData>({
    newPassword: '',
    confirmPassword: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  // パスワード強度計算
  const passwordStrengthResult = calculatePasswordStrength(formData.newPassword);
  const passwordStrength = (passwordStrengthResult.strength / 4) * 100; // Convert 0-4 scale to 0-100%

  /**
   * 入力値変更ハンドラー
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
    // エラーをクリア
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }));
    }
    setSubmitError(null);
  };

  /**
   * フォームバリデーション
   */
  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    // 新しいパスワードのバリデーション
    if (!formData.newPassword) {
      newErrors.newPassword = 'パスワードを入力してください';
    } else if (formData.newPassword.length < 8) {
      newErrors.newPassword = 'パスワードは8文字以上である必要があります';
    } else if (!/[A-Z]/.test(formData.newPassword)) {
      newErrors.newPassword = 'パスワードには大文字を含める必要があります';
    } else if (!/[a-z]/.test(formData.newPassword)) {
      newErrors.newPassword = 'パスワードには小文字を含める必要があります';
    } else if (!/[0-9]/.test(formData.newPassword)) {
      newErrors.newPassword = 'パスワードには数字を含める必要があります';
    }

    // パスワード確認のバリデーション
    if (!formData.confirmPassword) {
      newErrors.confirmPassword = 'パスワード（確認）を入力してください';
    } else if (formData.newPassword !== formData.confirmPassword) {
      newErrors.confirmPassword = 'パスワードが一致しません';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  /**
   * フォーム送信ハンドラー
   */
  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitError(null);

    // バリデーション
    if (!validateForm()) {
      return;
    }

    setIsSubmitting(true);

    try {
      await resetPassword(token, formData.newPassword);
      setSuccess(true);

      if (onSuccess) {
        // 2秒後にコールバックを実行（成功メッセージを表示する時間を確保）
        setTimeout(() => {
          onSuccess();
        }, 2000);
      }
    } catch (error: unknown) {
      const errorMessage = handleNetworkError(error);
      setSubmitError(errorMessage);

      if (onError) {
        onError(errorMessage);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  // 成功メッセージ表示
  if (success) {
    return (
      <div className="w-full max-w-md p-8 bg-white rounded-lg shadow-md">
        <div className="text-center">
          <div className="mb-4 text-green-600">
            <svg
              className="w-16 h-16 mx-auto"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M5 13l4 4L19 7"
              />
            </svg>
          </div>
          <h2 className="mb-2 text-2xl font-bold text-gray-900">パスワードをリセットしました</h2>
          <p className="text-gray-600">
            新しいパスワードでログインできます。
            <br />
            ログインページに移動しています...
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-md p-8 bg-white rounded-lg shadow-md">
      <h2 className="mb-6 text-2xl font-bold text-center text-gray-900">新しいパスワードを設定</h2>

      <form onSubmit={handleSubmit} noValidate>
        {submitError && <ErrorMessage message={submitError} className="mb-4" />}

        <InputField
          label="新しいパスワード"
          type="password"
          name="newPassword"
          value={formData.newPassword}
          onChange={handleChange}
          error={errors.newPassword}
          placeholder="新しいパスワードを入力"
          required
          autoComplete="new-password"
        />

        {/* パスワード強度インジケーター */}
        {formData.newPassword && (
          <div className="mb-4">
            <div className="flex items-center justify-between mb-1">
              <span className="text-sm text-gray-600">パスワード強度:</span>
              <span
                className={`text-sm font-medium ${
                  passwordStrength >= 80
                    ? 'text-green-600'
                    : passwordStrength >= 50
                      ? 'text-yellow-600'
                      : 'text-red-600'
                }`}
              >
                {passwordStrength >= 80 ? '強い' : passwordStrength >= 50 ? '普通' : '弱い'}
              </span>
            </div>
            <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
              <div
                className={`h-full transition-all duration-300 ${
                  passwordStrength >= 80
                    ? 'bg-green-500'
                    : passwordStrength >= 50
                      ? 'bg-yellow-500'
                      : 'bg-red-500'
                }`}
                style={{ width: `${passwordStrength}%` }}
              />
            </div>
          </div>
        )}

        <InputField
          label="パスワード（確認）"
          type="password"
          name="confirmPassword"
          value={formData.confirmPassword}
          onChange={handleChange}
          error={errors.confirmPassword}
          placeholder="パスワードを再入力"
          required
          autoComplete="new-password"
        />

        <Button type="submit" variant="primary" fullWidth loading={isSubmitting}>
          パスワードをリセット
        </Button>
      </form>

      <div className="mt-4 text-sm text-center text-gray-600">
        <p>パスワードの要件:</p>
        <ul className="mt-2 text-left list-disc list-inside">
          <li>8文字以上</li>
          <li>大文字を含む</li>
          <li>小文字を含む</li>
          <li>数字を含む</li>
        </ul>
      </div>
    </div>
  );
};

export default ResetPasswordForm;
