/**
 * ResetPasswordPage Component
 *
 * パスワードリセットページ。
 * URLからトークンを取得し、トークンの検証を行った後、ResetPasswordFormを表示します。
 *
 * ルート: /reset-password?token=xxx
 */

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { usePasswordReset } from '../hooks/usePasswordReset';
import ResetPasswordForm from '../components/ResetPasswordForm';
import { Navbar } from '../components';

/**
 * ResetPasswordPageコンポーネント
 * パスワードリセットフォームとレイアウトを提供します
 */
const ResetPasswordPage: React.FC = () => {
  const navigate = useNavigate();
  const { verifyResetToken } = usePasswordReset();
  const [searchParams] = useSearchParams();
  const token = searchParams.get('token');

  const [isVerifying, setIsVerifying] = useState(true);
  const [isValidToken, setIsValidToken] = useState(false);
  const [userEmail, setUserEmail] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  /**
   * トークン検証
   */
  useEffect(() => {
    const verifyToken = async () => {
      if (!token) {
        setIsVerifying(false);
        setIsValidToken(false);
        setErrorMessage('トークンが指定されていません。');
        return;
      }

      try {
        const result = await verifyResetToken(token);

        if (result.valid) {
          setIsValidToken(true);
          setUserEmail(result.email || null);
        } else {
          setIsValidToken(false);
          setErrorMessage(
            result.reason === 'Token expired/used/not found'
              ? 'このリセットリンクは無効です。期限切れまたは使用済みの可能性があります。'
              : 'トークンが無効です。'
          );
        }
      } catch (error: unknown) {
        setIsValidToken(false);
        setErrorMessage('トークンの検証中にエラーが発生しました。もう一度お試しください。');
      } finally {
        setIsVerifying(false);
      }
    };

    verifyToken();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  /**
   * パスワードリセット成功時のハンドラー
   */
  const handleResetSuccess = () => {
    // ログインページにリダイレクト
    navigate('/login', { replace: true });
  };

  /**
   * 読み込み中の表示
   */
  if (isVerifying) {
    return (
      <>
        <Navbar />
        <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
          <div className="sm:mx-auto sm:w-full sm:max-w-md">
            <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
              <div className="text-center">
                <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
                <p className="mt-4 text-gray-600">トークンを検証しています...</p>
              </div>
            </div>
          </div>
        </div>
      </>
    );
  }

  /**
   * トークンが無効な場合の表示
   */
  if (!isValidToken) {
    return (
      <>
        <Navbar />
        <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
          <div className="sm:mx-auto sm:w-full sm:max-w-md">
            <h1 className="text-center text-3xl font-bold text-gray-900">User Auth System</h1>
            <h2 className="mt-6 text-center text-2xl font-semibold text-gray-700">
              パスワードリセット
            </h2>
          </div>

          <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
            <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
              <div className="text-center">
                <div className="mb-4 text-red-600">
                  <svg
                    className="w-16 h-16 mx-auto"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
                    />
                  </svg>
                </div>
                <h3 className="mb-2 text-xl font-bold text-gray-900">無効なリンク</h3>
                <p className="mb-4 text-gray-600">{errorMessage}</p>
                <a
                  href="/forgot-password"
                  className="inline-block px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                >
                  新しいリセットリンクを送信
                </a>
              </div>
            </div>
          </div>

          <div className="mt-8 text-center">
            <p className="text-xs text-gray-500">
              &copy; 2025 User Auth System. All rights reserved.
            </p>
          </div>
        </div>
      </>
    );
  }

  /**
   * トークンが有効な場合の表示
   */
  return (
    <>
      <Navbar />
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
        <div className="sm:mx-auto sm:w-full sm:max-w-md">
          <h1 className="text-center text-3xl font-bold text-gray-900">User Auth System</h1>
          <h2 className="mt-6 text-center text-2xl font-semibold text-gray-700">
            パスワードリセット
          </h2>
          {userEmail && (
            <p className="mt-2 text-center text-sm text-gray-600">
              アカウント: <span className="font-medium">{userEmail}</span>
            </p>
          )}
        </div>

        <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
          <ResetPasswordForm token={token!} onSuccess={handleResetSuccess} />
        </div>

        <div className="mt-8 text-center">
          <p className="text-xs text-gray-500">
            &copy; 2025 User Auth System. All rights reserved.
          </p>
        </div>
      </div>
    </>
  );
};

export default ResetPasswordPage;
